        trace_id: str | None = None,
    ) -> p.Result[FlextObservability.Trace]:
        """Create a trace entity directly."""
        try:
            if not name:
                return r[FlextObservability.Trace].fail_op(
                    "create trace",
                    "Trace name must be non-empty string",
                )
